            Tags = """["sales-orders","sales","reference"]""",
            ContentJson = """{"title":"Sales Orders Field Reference","groups":[{"heading":"Order Details (New Order Window — Right Side)","items":[{"label":"Customer (required)","value":"Pick the customer from the menu. This sets who gets billed. You must choose one before you can save."},{"label":"Customer PO","value":"Optional. The customer's own purchase order number, for their reference. Shows on the list and the order."},{"label":"Credit Terms","value":"Optional. When payment is due — such as Due on Receipt, Net 15, Net 30, Net 45, Net 60, or Net 90. Pick from the menu."},{"label":"Requested Delivery Date","value":"Optional. When the customer wants the order delivered. Shows on the list and the order."},{"label":"Tax Rate (required)","value":"The tax percentage applied to the subtotal. Starts at 0 and can't be negative. The totals update as you type."},{"label":"Notes","value":"Optional. Free-form notes about the order — special instructions, packaging needs, and the like."}]},{"heading":"Line Item Fields (New Order Window — Left Side)","items":[{"label":"Part (required)","value":"Type to search active parts by number or description, then pick one. Only active parts appear."},{"label":"Qty (required)","value":"How many the customer wants. Starts at 1. Partial amounts are allowed."},{"label":"Unit Price (required)","value":"Price per unit. Starts at 0 and can't be negative."},{"label":"Add button","value":"Adds the line to the order. Stays off until the line is filled in correctly. The line fields clear so you can add the next one."},{"label":"Remove button (x icon)","value":"The red x on a line removes it from the order right away — no confirmation."}]},{"heading":"Line Item Columns (On the Order)","items":[{"label":"Part #","value":"The part number. Shows a dash when no part is linked."},{"label":"Description","value":"What the line is for."},{"label":"Qty","value":"How many were ordered."},{"label":"Shipped","value":"How many have shipped so far. Green once fully shipped, yellow when some but not all have shipped."},{"label":"Remaining","value":"How many are still to ship — ordered minus shipped."},{"label":"Unit Price","value":"Price per unit."},{"label":"Total","value":"The line total — quantity times unit price."}]},{"heading":"Order Statuses","items":[{"label":"Draft (gray)","value":"You're still preparing the order. Everything is editable, and you can delete or cancel it. New orders start here."},{"label":"Confirmed (blue)","value":"The order is confirmed and committed, and the confirmed date is set for you. You can still cancel it, but not delete it."},{"label":"In Production (teal)","value":"Linked jobs are active on the kanban board and work is underway."},{"label":"Partially Shipped (yellow)","value":"Some line items have shipped, but not all. Each line tracks its own shipped and remaining counts."},{"label":"Shipped (green)","value":"Every line item has fully shipped. Fulfillment is done."},{"label":"Completed (green)","value":"The order is fully closed — shipped and invoiced. Nothing left to do."},{"label":"Cancelled (red)","value":"The order was cancelled. You can cancel only from Draft or Confirmed; once it's in production, you can't."}]},{"heading":"List Columns","items":[{"label":"Order #","value":"The order's number. Click to sort."},{"label":"Customer","value":"The customer's name. Click to sort."},{"label":"Cust PO","value":"The customer's PO number. Shows a dash when there isn't one. Click to sort."},{"label":"Status","value":"The order's stage, shown as a colored label — Draft (gray), Confirmed (blue), In Production (teal), Partially Shipped (yellow), Shipped (green), Completed (green), Cancelled (red). Sort or filter by it."},{"label":"Lines","value":"How many line items the order has. Click to sort."},{"label":"Total","value":"The order total. Click to sort."},{"label":"Delivery","value":"The requested delivery date. Shows a dash when none is set. Click to sort."},{"label":"Created","value":"When the order was created. Click to sort."}]},{"heading":"List Filters","items":[{"label":"Search","value":"Filter by order number, customer name, or customer PO. Press Enter to search."},{"label":"Customer","value":"Pick a customer to see only their orders, or choose 'All Customers'."},{"label":"Status","value":"Pick a stage to see only orders at that stage, or choose 'All Statuses'."}]},{"heading":"What's on the Order","items":[{"label":"Header","value":"The order number and the customer name — click the name to open the customer."},{"label":"Status & Info","value":"The status, Customer PO, linked Quote (click to open it), Credit Terms, requested Delivery date, and Confirmed date. Each field appears only when it has a value."},{"label":"Barcode","value":"A scannable barcode for the order number."},{"label":"Totals","value":"Subtotal, Tax (with its rate), and the Total in bold."},{"label":"Notes","value":"Free-form notes, shown only when there are any."},{"label":"Line Items","value":"The full line list — part, description, quantity, shipped, remaining, unit price, and total. Shipped counts are color-coded."},{"label":"Dates","value":"When the order was created and last updated."},{"label":"Activity Log","value":"A running timeline of everything that happened to the order."}]},{"heading":"Buttons and Actions","items":[{"label":"New Sales Order","value":"Opens the new-order window. Sits in the page header."},{"label":"Create Order","value":"Saves the new order as a Draft. Stays off until the form is filled in and at least one line is added."},{"label":"Cancel (new-order window)","value":"Closes the new-order window without saving."},{"label":"Confirm","value":"Moves a Draft to Confirmed and records the confirmed date. Shows only on Draft orders."},{"label":"Cancel Order","value":"Cancels the order after you confirm. Available for Draft and Confirmed orders."},{"label":"Delete","value":"Removes a Draft order after you confirm. Available only on Draft orders."},{"label":"Close","value":"The x in the top-right corner closes the order and returns to the list."},{"label":"Row click","value":"Click a row to open that order. The address updates so you can bookmark or share the link."}]},{"heading":"What You Must Fill In","items":[{"label":"Customer","value":"Required. Pick a customer."},{"label":"Tax Rate","value":"Required. A number that can't be negative."},{"label":"Line Items","value":"Add at least one line, or you'll see 'At least one line item is required'."},{"label":"Line — Part","value":"Required. Pick a part from the search."},{"label":"Line — Quantity","value":"Required. Must be more than zero. Partial amounts are allowed."},{"label":"Line — Unit Price","value":"Required. Can't be negative."},{"label":"Why the button is off","value":"When something's missing, hover over Create Order to see a list of what still needs fixing."}]},{"heading":"The New-Order Window","items":[{"label":"Size","value":"A wide, two-side window."},{"label":"Left side (main)","value":"The line items: the list you've added, plus a row at the bottom to add another (part, quantity, price, and Add)."},{"label":"Right side","value":"Order details (customer, PO, credit terms, delivery date, tax rate), a Notes box, and a live Summary of subtotal, tax, and total."},{"label":"Footer","value":"Cancel on the left, Create Order on the right."},{"label":"Auto-save","value":"The window saves your work as you go, so an accidental reload or logout won't lose it. You'll be offered to pick up where you left off."}]}]}"""
