            Summary = "Edge-case and power-user notes: Schedule-tab at-risk milestones, Returns-tab job links, fractional qty / 4-decimal pricing, create-dialog draft auto-save, and why the line table is read-only after Draft.",
            ContentType = TrainingContentType.Reference,
